.darma-loader-cssloaders-github-28 {
  display: inline-block;
  width: 51px;
  height: 51px;
  border-radius: 12px;
  background: linear-gradient(135deg, var(--loader-color, #6366f1), var(--loader-secondary-color, #a5b4fc));
  animation: darma-loader-cssloaders-github-28-squareFlip 0.85s cubic-bezier(.55,.08,.38,.97) infinite;
}
